1	package server
2	
3	import (
4		"bytes"
5		"encoding/json"
6		"net/http"
7		"net/http/httptest"
8		"strings"
9		"testing"
10	
11		"github.com/DocumentDrivenDX/ddx/internal/federation"
12	)
13	
14	// federationDoRequest is a small helper that runs a request against an
15	// httptest.NewServer wrapping s.Handler() so we exercise the real net/http
16	// stack (RemoteAddr is populated by the test server, matching production
17	// trust-gating behavior). Pass remote="loopback" for trusted, "external"
18	// for an explicitly non-loopback request.
19	func federationDoRequest(t *testing.T, s *Server, method, path string, body any, remote string) *http.Response {
20		t.Helper()
21		var buf bytes.Buffer
22		if body != nil {
23			if err := json.NewEncoder(&buf).Encode(body); err != nil {
24				t.Fatalf("encode: %v", err)
25			}
26		}
27		req := httptest.NewRequest(method, path, &buf)
28		req.Header.Set("Content-Type", "application/json")
29		switch remote {
30		case "external":
31			req.RemoteAddr = "203.0.113.1:54321"
32		default:
33			req.RemoteAddr = "127.0.0.1:54321"
34		}
35		rec := httptest.NewRecorder()
36		s.Handler().ServeHTTP(rec, req)
37		return rec.Result()
38	}
39	
40	func newHubServer(t *testing.T, allowPlainHTTP bool) *Server {
41		t.Helper()
42		dir := setupTestDir(t)
43		s := New(":0", dir)
44		s.EnableHubMode(allowPlainHTTP)
45		// Pin hub version for handshake tests.
46		s.hub.hubDDxVersion = "0.10.5"
47		s.hub.hubSchemaVer = "1"
48		return s
49	}
50	
51	func decodeBody(t *testing.T, resp *http.Response, dst any) {
52		t.Helper()
53		if err := json.NewDecoder(resp.Body).Decode(dst); err != nil {
54			t.Fatalf("decode: %v", err)
55		}
56	}
57	
58	// AC: Routes mounted only when --hub-mode.
59	func TestFederationRoutesNotMountedWithoutHubMode(t *testing.T) {
60		dir := setupTestDir(t)
61		s := New(":0", dir)
62		// Hub mode NOT enabled — federation routes must not be on the mux at all.
63		for _, p := range s.routePatterns {
64			if strings.Contains(p, "/api/federation/") {
65				t.Fatalf("federation route registered without EnableHubMode: %s", p)
66			}
67		}
68		// And a register request must not produce a federation register response
69		// (no node_id-bearing JSON body); the request falls through to the SPA
70		// fallback or a non-2xx error, but never the federation handler.
71		resp := federationDoRequest(t, s, "POST", "/api/federation/register",
72			map[string]string{"node_id": "n1"}, "loopback")
73		var maybe federationRegisterResponse
74		_ = json.NewDecoder(resp.Body).Decode(&maybe)
75		if maybe.NodeID == "n1" {
76			t.Fatalf("federation register handler ran with hub-mode off")
77		}
78	}
79	
80	// AC: routes mounted when hub-mode enabled.
81	func TestFederationRoutesMountedInHubMode(t *testing.T) {
82		s := newHubServer(t, false)
83		want := []string{
84			"POST /api/federation/register",
85			"POST /api/federation/heartbeat",
86			"GET /api/federation/spokes",
87			"DELETE /api/federation/spokes/{id}",
88		}
89		have := map[string]bool{}
90		for _, p := range s.routePatterns {
91			have[p] = true
92		}
93		for _, p := range want {
