130		// Should complete in well under the slow spoke's 2s wait.
131		if elapsed > 1500*time.Millisecond {
132			t.Fatalf("fan-out took %s — slow spoke blocked others", elapsed)
133		}
134		if _, ok := res.Responses[fast.NodeID]; !ok {
135			t.Fatalf("fast spoke missing from responses: %+v", res)
136		}
137		if _, ok := res.Errors[slow.NodeID]; !ok {
138			t.Fatalf("slow spoke missing from errors: %+v", res.Errors)
139		}
140		// Per-node timeout must not flip the spoke to offline (could just be stale).
141		if _, ok := res.StatusUpdates[slow.NodeID]; ok {
142			t.Fatalf("per-node timeout must not produce a status update; got %+v", res.StatusUpdates)
143		}
144		// The per-node detail should classify the slow spoke as OutcomeTimeout.
145		var found bool
146		for _, n := range res.Nodes {
147			if n.NodeID == slow.NodeID {
148				if n.Outcome != OutcomeTimeout {
149					t.Fatalf("slow spoke outcome = %q, want %q", n.Outcome, OutcomeTimeout)
150				}
151				found = true
152			}
153		}
154		if !found {
155			t.Fatalf("slow spoke not present in Nodes")
156		}
157	}
