341	// TestFanOut_MidResponseDisconnect simulates a spoke that accepts the
342	// connection, writes partial body, then forcibly closes mid-response.
343	func TestFanOut_MidResponseDisconnect(t *testing.T) {
344		ln, err := net.Listen("tcp", "127.0.0.1:0")
345		if err != nil {
346			t.Fatalf("listen: %v", err)
347		}
348		t.Cleanup(func() { _ = ln.Close() })
349	
350		go func() {
351			for {
352				conn, err := ln.Accept()
353				if err != nil {
354					return
355				}
356				go func(c net.Conn) {
357					defer func() { _ = c.Close() }()
358					// Read request roughly.
359					buf := make([]byte, 4096)
360					_ = c.SetReadDeadline(time.Now().Add(500 * time.Millisecond))
361					_, _ = c.Read(buf)
362					// Send headers claiming larger Content-Length, then close mid-body.
363					_, _ = io.WriteString(c, "HTTP/1.1 200 OK\r\nContent-Type: application/json\r\nContent-Length: 1024\r\n\r\n")
364					_, _ = io.WriteString(c, `{"data":`)
365					// Drop the connection.
366				}(conn)
367			}
368		}()
369	
370		rec := SpokeRecord{
371			NodeID:        "flaky",
372			URL:           "http://" + ln.Addr().String(),
373			DDxVersion:    "0.1.0",
374			SchemaVersion: CurrentSchemaVersion,
375			Status:        StatusActive,
376		}
377		c := NewFanOutClient()
378		c.HubDDxVersion = "0.1.0"
379		c.HubSchemaVersion = CurrentSchemaVersion
380		c.PerNodeTimeout = 1 * time.Second
381	
382		res, err := c.Execute(context.Background(), []SpokeRecord{rec}, &FanOutRequest{Query: "{ __typename }"})
383		if err != nil {
384			t.Fatalf("execute: %v", err)
385		}
386		if _, ok := res.Errors[rec.NodeID]; !ok {
387			t.Fatalf("expected mid-response disconnect to surface as an error; got %+v", res)
388		}
389		if got := res.StatusUpdates[rec.NodeID]; got != StatusOffline {
390			t.Fatalf("mid-response disconnect status = %q, want %q", got, StatusOffline)
391		}
392	}
