14	// federationSpoke holds the per-server state for spoke-mode federation: the
15	// running spoke lifecycle agent and its config (so tests can introspect what
16	// was advertised to the hub).
17	type federationSpoke struct {
18		agent   *federation.Spoke
19		hubURL  string
20		selfURL string
21	}
22	
23	// EnableSpokeMode launches the spoke-side lifecycle: register-on-start,
24	// jittered heartbeat, URL-change detection across restarts, and best-effort
25	// deregister-on-shutdown. Idempotent: a second call is a no-op.
26	//
27	// hubURL is the federation hub base URL (e.g. "https://hub:7743").
28	// selfURL is this server's externally-reachable URL advertised to the hub
29	// (e.g. "https://node-a:7743"). When empty, a default is constructed from
30	// the bind address.
31	//
32	// The returned error reflects the initial registration outcome — if the hub
33	// rejects the registration (version mismatch, identity conflict, etc.) the
34	// spoke does not start.
35	//
36	// Both EnableHubMode and EnableSpokeMode may be called on the same server
37	// (hub_spoke role).
38	func (s *Server) EnableSpokeMode(ctx context.Context, hubURL, selfURL string, opts ...SpokeOption) error {
39		if s.spoke != nil {
40			return nil
41		}
42		if strings.TrimSpace(hubURL) == "" {
43			return fmt.Errorf("federation: --hub URL required for spoke mode")
44		}
45		if strings.TrimSpace(selfURL) == "" {
46			// Best-effort default: scheme is https + bind address. Operators can
47			// override via the explicit selfURL arg.
48			selfURL = "https://" + s.Addr
49		}
50	
51		cfg := federation.SpokeConfig{
52			NodeID:        s.state.Node.ID,
53			Name:          s.state.Node.Name,
54			URL:           selfURL,
55			HubURL:        hubURL,
56			DDxVersion:    HubDefaultDDxVersion,
57			SchemaVersion: federation.CurrentSchemaVersion,
58			Logger:        func(format string, args ...any) { log.Printf("WARN: "+format, args...) },
59		}
60		for _, opt := range opts {
61			opt(&cfg)
62		}
63	
64		agent, err := federation.NewSpoke(cfg)
65		if err != nil {
66			return err
67		}
68	
69		if agent.URLChanged() {
70			log.Printf("federation: spoke URL changed from %q to %q; will re-register with new URL",
71				agent.PreviousURL(), selfURL)
72		}
73	
74		if err := agent.Start(ctx); err != nil {
75			return fmt.Errorf("federation: spoke register: %w", err)
76		}
77	
78		s.spoke = &federationSpoke{agent: agent, hubURL: hubURL, selfURL: selfURL}
79		s.SpokeMode = true
80		return nil
81	}
82	
83	// SpokeOption customises the SpokeConfig used by EnableSpokeMode. Tests use
84	// it to install short heartbeat intervals and a fake HTTP client.
85	type SpokeOption func(*federation.SpokeConfig)
86	
87	// WithSpokeHeartbeatInterval overrides the heartbeat cadence.
88	func WithSpokeHeartbeatInterval(d time.Duration) SpokeOption {
89		return func(c *federation.SpokeConfig) { c.HeartbeatInterval = d }
90	}
91	
92	// WithSpokeHeartbeatJitter overrides the heartbeat jitter fraction.
93	func WithSpokeHeartbeatJitter(j float64) SpokeOption {
94		return func(c *federation.SpokeConfig) { c.HeartbeatJitterFraction = j }
95	}
96	
97	// WithSpokeStatePath overrides the spoke-state.json path.
98	func WithSpokeStatePath(p string) SpokeOption {
99		return func(c *federation.SpokeConfig) { c.StatePath = p }
100	}
101	
102	// WithSpokeHTTPClient overrides the HTTP client used to call the hub.
103	func WithSpokeHTTPClient(client *http.Client) SpokeOption {
104		return func(c *federation.SpokeConfig) { c.HTTPClient = client }
105	}
106	
107	// WithSpokeSelfURL overrides the spoke's self-URL after defaults are applied.
108	// Useful when a caller wants to advertise a different URL than the bind addr.
109	func WithSpokeSelfURL(url string) SpokeOption {
110		return func(c *federation.SpokeConfig) { c.URL = url }
111	}
112	
113	// WithSpokeNodeID overrides the node_id advertised to the hub. Useful for
114	// tests where the server's persisted node_id is not deterministic.
115	func WithSpokeNodeID(id string) SpokeOption {
116		return func(c *federation.SpokeConfig) { c.NodeID = id }
117	}
118	
119	// SpokeAgent exposes the underlying federation.Spoke for tests and operator
120	// introspection. Returns nil if spoke mode is not enabled.
121	func (s *Server) SpokeAgent() *federation.Spoke {
122		if s.spoke == nil {
123			return nil
124		}
125		return s.spoke.agent
126	}
127	
128	// ShutdownSpoke stops the spoke lifecycle (heartbeat + best-effort deregister).
129	// Safe to call when spoke mode is not enabled — returns nil. Called from
130	// graceful shutdown paths so the hub registry does not show a stale spoke.
131	func (s *Server) ShutdownSpoke(ctx context.Context) error {
132		if s.spoke == nil {
133			return nil
134		}
135		return s.spoke.agent.Shutdown(ctx)
136	}
