126	// SpokeConfig configures a Spoke lifecycle agent. URL is the spoke's own
127	// publicly-reachable URL (advertised to the hub); HubURL is the hub base URL
128	// (e.g. "https://hub.example:7743").
129	type SpokeConfig struct {
130		NodeID               string
131		Name                 string
132		URL                  string
133		HubURL               string
134		DDxVersion           string
135		SchemaVersion        string
136		GraphQLSchemaVersion string
137		Capabilities         []string
138	
139		// HeartbeatInterval defaults to DefaultHeartbeatInterval. Pass a small
140		// value (e.g. 50ms) in tests.
141		HeartbeatInterval time.Duration
142		// HeartbeatJitterFraction is the ± jitter as a fraction of the interval
143		// (e.g. 0.25 for ±25%). Defaults to DefaultHeartbeatJitterFraction.
144		HeartbeatJitterFraction float64
145		// DeregisterTimeout caps the best-effort deregister on shutdown.
146		DeregisterTimeout time.Duration
147	
148		// StatePath is the disk path for spoke-state.json. Empty → DefaultSpokeStatePath.
149		StatePath string
150		// HTTPClient is used for hub requests. Nil → default client that accepts
151		// self-signed certs (matches the server's auto-generated cert).
152		HTTPClient *http.Client
153		// Logger is used for warn/info; nil → log.Printf.
154		Logger func(format string, args ...any)
155	}
156	
157	// Spoke is the spoke-side lifecycle agent: register on Start, jittered
158	// heartbeat in the background, deregister best-effort on Shutdown.
159	type Spoke struct {
160		cfg                 SpokeConfig
161		identityFingerprint string
162	
163		mu              sync.Mutex
164		statePath       string
165		registered      bool
166		stopped         chan struct{}
167		stopOnce        sync.Once
168		registeredCount int // test introspection
169		heartbeatCount  int // test introspection
170		urlChanged      bool
171		urlChangedFrom  string
172		hbErr           error
173		logf            func(format string, args ...any)
174	}
175	
176	// NewSpoke constructs a Spoke with defaults filled in. The spoke is not
177	// started until Start is called.
178	func NewSpoke(cfg SpokeConfig) (*Spoke, error) {
179		if strings.TrimSpace(cfg.NodeID) == "" {
180			return nil, fmt.Errorf("federation: spoke NodeID required")
181		}
182		if strings.TrimSpace(cfg.HubURL) == "" {
183			return nil, fmt.Errorf("federation: spoke HubURL required")
184		}
185		if strings.TrimSpace(cfg.URL) == "" {
186			return nil, fmt.Errorf("federation: spoke URL required")
187		}
188		if cfg.HeartbeatInterval <= 0 {
189			cfg.HeartbeatInterval = DefaultHeartbeatInterval
190		}
191		if cfg.HeartbeatJitterFraction < 0 {
192			cfg.HeartbeatJitterFraction = 0
193		}
194		if cfg.HeartbeatJitterFraction == 0 {
195			cfg.HeartbeatJitterFraction = DefaultHeartbeatJitterFraction
196		}
197		if cfg.DeregisterTimeout <= 0 {
198			cfg.DeregisterTimeout = DefaultDeregisterTimeout
199		}
200		if cfg.HTTPClient == nil {
201			// Self-signed certs are the default for ddx-server, so the spoke
202			// must skip cert verification by default. Operators wanting stricter
203			// validation can pass a custom HTTPClient.
204			cfg.HTTPClient = &http.Client{
205				Timeout: 10 * time.Second,
206				Transport: &http.Transport{
207					TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
208				},
209			}
210		}
211	
212		statePath := cfg.StatePath
213		if statePath == "" {
214			p, err := DefaultSpokeStatePath()
215			if err != nil {
216				return nil, err
217			}
218			statePath = p
219		}
220	
221		logf := cfg.Logger
222		if logf == nil {
223			logf = func(format string, args ...any) { log.Printf(format, args...) }
224		}
225	
226		st, err := LoadSpokeState(statePath)
227		if err != nil {
228			return nil, err
229		}
230	
231		// Detect URL change between restarts.
232		var urlChanged bool
233		var prevURL string
234		if st.NodeID == cfg.NodeID && st.LastURL != "" && st.LastURL != cfg.URL {
235			urlChanged = true
236			prevURL = st.LastURL
237		}
238	
239		// Reuse fingerprint if it's for the same node_id; otherwise generate one.
240		fp := st.IdentityFingerprint
241		if fp == "" || st.NodeID != cfg.NodeID {
242			fp = generateIdentityFingerprint()
243		}
244	
245		s := &Spoke{
246			cfg:                 cfg,
247			identityFingerprint: fp,
248			statePath:           statePath,
249			stopped:             make(chan struct{}),
250			urlChanged:          urlChanged,
251			urlChangedFrom:      prevURL,
252			logf:                logf,
253		}
254		return s, nil
255	}
