10	// HandshakeResult is the outcome of validating a spoke's version handshake
11	// against the hub's own version + schema version.
12	type HandshakeResult struct {
13		// Accept reports whether the registration should be accepted at all.
14		Accept bool
15		// Status is the SpokeStatus to record on accepted registrations:
16		// StatusRegistered when fully compatible (heartbeat will move it to
17		// StatusActive), or StatusDegraded when accepted-but-newer.
18		Status SpokeStatus
19		// Reason is a short, machine-readable code for the outcome — used as the
20		// rejection reason on 4xx and as a degraded-status reason on accept.
21		// Stable enum: "ok", "degraded_newer_minor",
22		// "schema_mismatch", "ddx_major_mismatch", "missing_ddx_version",
23		// "missing_schema_version", "invalid_ddx_version".
24		Reason string
25	}
26	
27	// Handshake validates a spoke's version handshake.
28	//
29	//   - schema_version must match the hub's schema version exactly. Anything
30	//     else is rejected ("schema_mismatch").
31	//   - ddx_version must parse as semver. Major version must match the hub.
32	//     A higher minor or patch on the spoke side accepts as StatusDegraded
33	//     ("degraded_newer_minor"). Equal-or-lower minors/patches accept as
34	//     StatusRegistered ("ok"). Mismatched majors are rejected
35	//     ("ddx_major_mismatch").
36	//
37	// Empty / unparseable inputs are rejected with descriptive reasons.
38	func Handshake(hubDDxVersion, hubSchemaVersion, spokeDDxVersion, spokeSchemaVersion string) HandshakeResult {
39		if strings.TrimSpace(spokeSchemaVersion) == "" {
40			return HandshakeResult{Reason: "missing_schema_version"}
41		}
42		if spokeSchemaVersion != hubSchemaVersion {
43			return HandshakeResult{Reason: "schema_mismatch"}
44		}
45		if strings.TrimSpace(spokeDDxVersion) == "" {
46			return HandshakeResult{Reason: "missing_ddx_version"}
47		}
48		hubParts, err := update.ParseVersion(hubDDxVersion)
49		if err != nil {
50			return HandshakeResult{Reason: fmt.Sprintf("invalid_hub_ddx_version:%v", err)}
51		}
52		spokeParts, err := update.ParseVersion(spokeDDxVersion)
53		if err != nil {
54			return HandshakeResult{Reason: "invalid_ddx_version"}
55		}
56		if spokeParts[0] != hubParts[0] {
57			return HandshakeResult{Reason: "ddx_major_mismatch"}
58		}
59		// Same major, compare minor.patch. Any newer minor or patch on the spoke
60		// side is "compatible-but-newer" → degraded.
61		newer := spokeParts[1] > hubParts[1] ||
62			(spokeParts[1] == hubParts[1] && spokeParts[2] > hubParts[2])
63		if newer {
64			return HandshakeResult{Accept: true, Status: StatusDegraded, Reason: "degraded_newer_minor"}
65		}
66		return HandshakeResult{Accept: true, Status: StatusRegistered, Reason: "ok"}
67	}
